INSERT INTO public.schemes (name_en, name_te, description_en, description_te, category, ministry, eligibility_en, eligibility_te, benefits_en, benefits_te, documents, apply_url, state) VALUES
('Pradhan Mantri Mudra Yojana (PMMY)', 'ప్రధాన మంత్రి ముద్రా యోజన', 'Collateral-free loans up to ₹10 lakh for micro and small non-corporate enterprises.', 'సూక్ష్మ మరియు చిన్న వ్యాపారాలకు ₹10 లక్షల వరకు పూచీకత్తు లేని రుణాలు.', 'MSME', 'Ministry of Finance', 'Any Indian citizen with a business plan for a non-farm income-generating activity.', 'వ్యవసాయేతర వ్యాపార ప్రణాళిక ఉన్న ఏ భారతీయ పౌరుడైనా.', 'Loans under Shishu (up to ₹50k), Kishor (₹50k-5L), Tarun (₹5L-10L).', 'శిశు, కిషోర్, తరుణ్ వర్గాల్లో రుణాలు.', ARRAY['Aadhaar','PAN','Business proof','Bank statements','Quotation/Invoice'], 'https://www.mudra.org.in', 'All India'),
('Stand Up India', 'స్టాండ్ అప్ ఇండియా', 'Bank loans between ₹10 lakh and ₹1 crore for SC/ST and women entrepreneurs.', 'SC/ST మరియు మహిళా వ్యవస్థాపకులకు ₹10 లక్షల నుండి ₹1 కోటి వరకు రుణాలు.', 'Women', 'Ministry of Finance', 'SC/ST or woman aged 18+ setting up a greenfield enterprise in manufacturing, services, or trading.', '18+ వయసు SC/ST లేదా మహిళలు కొత్త వ్యాపారం స్థాపించడానికి.', 'Composite loan (term + working capital) covering 75% of project cost.', 'ప్రాజెక్ట్ ఖర్చులో 75% వరకు రుణం.', ARRAY['Aadhaar','PAN','Caste/Gender proof','Project report','Bank details'], 'https://www.standupmitra.in', 'All India'),
('Atal Pension Yojana (APY)', 'అటల్ పెన్షన్ యోజన', 'Guaranteed monthly pension of ₹1,000–₹5,000 after age 60 for unorganized sector workers.', '60 ఏళ్ళ తర్వాత నెలవారీ గ్యారెంటీ పెన్షన్ ₹1,000–₹5,000.', 'Social Security', 'Ministry of Finance', 'Indian citizens aged 18-40 with a savings bank account.', 'సేవింగ్స్ ఖాతా ఉన్న 18-40 ఏళ్ళ భారతీయులు.', 'Lifetime monthly pension after 60; corpus returned to nominee on death.', '60 తర్వాత జీవితకాల పెన్షన్.', ARRAY['Aadhaar','Mobile number','Savings bank account'], 'https://www.npscra.nsdl.co.in/scheme-details.php', 'All India'),
('Pradhan Mantri Jeevan Jyoti Bima Yojana', 'ప్రధాన మంత్రి జీవన్ జ్యోతి బీమా యోజన', 'Life insurance cover of ₹2 lakh for just ₹436/year.', 'కేవలం ₹436/సంవత్సరానికి ₹2 లక్షల జీవిత బీమా.', 'Insurance', 'Ministry of Finance', 'Indian residents aged 18-50 with a bank account.', 'బ్యాంక్ ఖాతా ఉన్న 18-50 ఏళ్ళ భారతీయులు.', '₹2,00,000 payable to nominee on death from any cause.', 'మరణిస్తే నామినీకి ₹2,00,000.', ARRAY['Aadhaar','Bank account','Consent form'], 'https://www.jansuraksha.gov.in', 'All India'),
('Pradhan Mantri Suraksha Bima Yojana', 'ప్రధాన మంత్రి సురక్షా బీమా యోజన', 'Accidental death and disability cover of ₹2 lakh for ₹20/year.', '₹20/సంవత్సరానికి ₹2 లక్షల ప్రమాద బీమా.', 'Insurance', 'Ministry of Finance', 'Indian residents aged 18-70 with a bank account.', 'బ్యాంక్ ఖాతా ఉన్న 18-70 ఏళ్ళ భారతీయులు.', '₹2,00,000 for accidental death; ₹1,00,000 for partial disability.', 'ప్రమాద మరణానికి ₹2,00,000.', ARRAY['Aadhaar','Bank account','Consent form'], 'https://www.jansuraksha.gov.in', 'All India'),
('PM Vishwakarma Yojana', 'PM విశ్వకర్మ యోజన', 'Support for traditional artisans and craftspeople with training, toolkit grant, and credit.', 'సాంప్రదాయ హస్తకళాకారులకు శిక్షణ, టూల్‌కిట్ గ్రాంట్ మరియు రుణం.', 'Skill Development', 'Ministry of MSME', 'Artisans in 18 trades (carpenter, blacksmith, potter, tailor, barber, etc.) aged 18+.', '18 వృత్తులలోని హస్తకళాకారులు.', '₹15k toolkit, ₹500/day stipend during training, ₹1L collateral-free loan @5%, marketing support.', '₹15k టూల్‌కిట్, ₹1L రుణం @5%, శిక్షణ.', ARRAY['Aadhaar','Caste certificate (if applicable)','Bank account','Mobile number'], 'https://pmvishwakarma.gov.in', 'All India'),
('Skill India Mission (PMKVY)', 'స్కిల్ ఇండియా (PMKVY)', 'Free short-term skill training and certification for youth.', 'యువతకు ఉచిత స్వల్పకాలిక నైపుణ్య శిక్షణ.', 'Skill Development', 'Ministry of Skill Development', 'Indian youth aged 15-45, especially school/college dropouts.', '15-45 ఏళ్ళ భారతీయ యువత.', 'Free training in 250+ job roles, NSQF-aligned certificate, placement support.', '250+ ఉద్యోగాలలో ఉచిత శిక్షణ.', ARRAY['Aadhaar','Bank account','Educational qualification proof'], 'https://www.pmkvyofficial.org', 'All India'),
('Sukanya Samriddhi Yojana', 'సుకన్యా సమృద్ధి యోజన', 'Small savings scheme for girl child with high interest and tax benefits.', 'ఆడపిల్లల కోసం అధిక వడ్డీతో పొదుపు పథకం.', 'Women', 'Ministry of Finance', 'Parents/legal guardians of a girl child below 10 years.', '10 ఏళ్ళలోపు ఆడపిల్లల తల్లిదండ్రులు.', '8.2% p.a. interest, EEE tax status, deposits up to ₹1.5L/year.', '8.2% వడ్డీ, ₹1.5L వరకు ఆదాయపన్ను మినహాయింపు.', ARRAY['Aadhaar (girl & guardian)','Birth certificate of girl','Address proof'], 'https://www.india.gov.in/sukanya-samriddhi-yojna', 'All India'),
('Beti Bachao Beti Padhao', 'బేటీ బచావో బేటీ పఢావో', 'Scheme to address declining child sex ratio and promote girls'' education.', 'ఆడపిల్లల విద్యను ప్రోత్సహించే పథకం.', 'Women', 'Ministry of Women & Child', 'All families with girl children; awareness and welfare across India.', 'ఆడపిల్లలు ఉన్న అన్ని కుటుంబాలు.', 'Awareness, education incentives, healthcare for girl children.', 'ఆడపిల్లల విద్య మరియు ఆరోగ్యానికి సహాయం.', ARRAY['Aadhaar','Birth certificate','Income proof'], 'https://wcd.nic.in/bbbp-schemes', 'All India'),
('Janani Suraksha Yojana', 'జననీ సురక్షా యోజన', 'Cash assistance to promote institutional delivery for pregnant women.', 'గర్భిణీ స్త్రీలకు ఆస్పత్రి ప్రసవానికి నగదు సహాయం.', 'Health', 'Ministry of Health', 'Pregnant women from BPL, SC/ST families, especially in low-performing states.', 'BPL, SC/ST గర్భిణీ స్త్రీలు.', '₹1,400 (rural) / ₹1,000 (urban) cash assistance + free delivery care.', '₹1,400 వరకు నగదు + ఉచిత ప్రసవ సేవలు.', ARRAY['Aadhaar','MCP card','BPL/Caste certificate','Bank account'], 'https://nhm.gov.in/index1.php?lang=1&level=3&sublinkid=841&lid=309', 'All India'),
('Pradhan Mantri Matru Vandana Yojana', 'ప్రధాన మంత్రి మాతృ వందన యోజన', 'Cash benefit of ₹5,000 to pregnant and lactating mothers for first living child.', 'మొదటి బిడ్డకు గర్భిణీ స్త్రీలకు ₹5,000 నగదు.', 'Women', 'Ministry of Women & Child', 'Pregnant and lactating mothers aged 19+ for first live birth.', '19+ గర్భిణీ స్త్రీలు, మొదటి బిడ్డ.', '₹5,000 in three installments, plus JSY benefits.', '₹5,000 మూడు విడతలలో.', ARRAY['Aadhaar','MCP card','Bank account','Husband Aadhaar'], 'https://wcd.nic.in/schemes/pradhan-mantri-matru-vandana-yojana', 'All India'),
('Mid Day Meal Scheme (PM POSHAN)', 'మధ్యాహ్న భోజన పథకం', 'Free hot cooked meals to school children to improve nutrition and attendance.', 'పాఠశాల పిల్లలకు ఉచిత మధ్యాహ్న భోజనం.', 'Education', 'Ministry of Education', 'All children in government and government-aided schools (Class 1-8).', '1-8 తరగతుల ప్రభుత్వ పాఠశాల విద్యార్థులు.', 'Free nutritious meal on every school day.', 'ప్రతి పాఠశాల రోజు ఉచిత భోజనం.', ARRAY['School enrollment'], 'https://pmposhan.education.gov.in', 'All India'),
('National Scholarship Portal Schemes', 'జాతీయ స్కాలర్‌షిప్ పోర్టల్', 'Single platform for central and state government scholarships.', 'కేంద్ర & రాష్ట్ర స్కాలర్‌షిప్‌లకు ఏకీకృత పోర్టల్.', 'Education', 'Ministry of Electronics & IT', 'Students from minority, SC/ST/OBC, EWS, disabled categories.', 'మైనారిటీ, SC/ST/OBC, EWS, దివ్యాంగ విద్యార్థులు.', 'Pre-matric, post-matric and merit-cum-means scholarships.', 'ప్రీ/పోస్ట్-మెట్రిక్ స్కాలర్‌షిప్‌లు.', ARRAY['Aadhaar','Income certificate','Caste certificate','Bank account','Marks card'], 'https://scholarships.gov.in', 'All India'),
('Atal Innovation Mission', 'అటల్ ఇన్నోవేషన్ మిషన్', 'Promotes innovation and entrepreneurship through Atal Tinkering Labs and Incubators.', 'ఆవిష్కరణ మరియు వ్యవస్థాపకత ప్రోత్సాహం.', 'Education', 'NITI Aayog', 'Schools, universities, startups, and individual innovators.', 'పాఠశాలలు, స్టార్టప్‌లు, ఆవిష్కర్తలు.', 'Grants up to ₹10 crore for incubators; mentoring and infrastructure.', '₹10 కోట్ల వరకు గ్రాంట్‌లు.', ARRAY['Institution registration','Project proposal','Aadhaar'], 'https://aim.gov.in', 'All India'),
('Saubhagya - Pradhan Mantri Sahaj Bijli Har Ghar Yojana', 'సౌభాగ్య యోజన', 'Universal household electrification scheme.', 'అన్ని ఇళ్ళకు విద్యుత్ కనెక్షన్.', 'Energy', 'Ministry of Power', 'All un-electrified rural and poor urban households.', 'విద్యుత్ లేని గ్రామీణ & పేద పట్టణ ఇళ్ళు.', 'Free electricity connection for BPL; ₹500 in 10 installments for others.', 'BPL కి ఉచిత కనెక్షన్.', ARRAY['Aadhaar','Address proof','BPL certificate'], 'https://saubhagya.gov.in', 'All India'),
('Pradhan Mantri Ujjwala Yojana 2.0', 'ప్రధాన మంత్రి ఉజ్జ్వల యోజన', 'Free LPG connection to women from poor households.', 'పేద కుటుంబాల మహిళలకు ఉచిత LPG కనెక్షన్.', 'Energy', 'Ministry of Petroleum', 'Adult woman from BPL/SC/ST/OBC/PMAY/AAY households without LPG.', 'LPG లేని పేద కుటుంబాల మహిళలు.', 'Free LPG connection, first refill and stove free.', 'ఉచిత గ్యాస్ కనెక్షన్ + స్టవ్.', ARRAY['Aadhaar','Ration card','BPL/Self-declaration','Bank account','Photo'], 'https://www.pmuy.gov.in', 'All India'),
('PM Surya Ghar - Muft Bijli Yojana', 'PM సూర్య ఘర్ ముఫ్త్ బిజిలీ యోజన', 'Rooftop solar scheme providing free electricity up to 300 units/month.', 'ఇంటి పైకప్పు సోలార్ ద్వారా ఉచిత విద్యుత్.', 'Energy', 'Ministry of New & Renewable Energy', 'Indian household owning a roof; valid electricity connection.', 'సొంత ఇల్లు & విద్యుత్ కనెక్షన్ ఉన్న కుటుంబాలు.', 'Subsidy up to ₹78,000 for 3kW system; free 300 units/month.', '₹78,000 వరకు సబ్సిడీ.', ARRAY['Aadhaar','Electricity bill','Roof ownership proof','Bank account'], 'https://pmsuryaghar.gov.in', 'All India'),
('Pradhan Mantri Awas Yojana - Gramin', 'PM ఆవాస్ యోజన - గ్రామీణ', 'Pucca house with basic amenities for homeless rural families.', 'గ్రామీణ నిరాశ్రయులకు పక్కా ఇల్లు.', 'Housing', 'Ministry of Rural Development', 'Houseless/kutcha-house rural families per SECC 2011 list.', 'SECC 2011 జాబితాలో ఉన్న గ్రామీణ కుటుంబాలు.', '₹1.2L (plains) / ₹1.3L (hilly) financial assistance + toilet under SBM.', '₹1.2L వరకు ఆర్థిక సహాయం.', ARRAY['Aadhaar','Bank account','SECC ID','Job card (MGNREGA)'], 'https://pmayg.nic.in', 'All India'),
('Deendayal Antyodaya Yojana - NRLM', 'DAY-NRLM', 'Reduces poverty by promoting self-employment and SHGs for rural women.', 'గ్రామీణ మహిళలకు SHGs ద్వారా స్వయం ఉపాధి.', 'Rural Development', 'Ministry of Rural Development', 'Rural poor women organized into Self Help Groups.', 'SHGలోని గ్రామీణ పేద మహిళలు.', 'Revolving funds, community investment, interest subvention on bank loans.', 'రుణాలపై వడ్డీ సబ్సిడీ.', ARRAY['Aadhaar','SHG membership','Bank account'], 'https://aajeevika.gov.in', 'All India'),
('MGNREGA', 'MGNREGA', 'Guaranteed 100 days of wage employment per rural household per year.', 'గ్రామీణ కుటుంబానికి సంవత్సరానికి 100 రోజుల ఉపాధి గ్యారెంటీ.', 'Employment', 'Ministry of Rural Development', 'Adult members of rural households willing to do unskilled manual work.', 'మాన్యువల్ పని చేయడానికి సిద్ధంగా ఉన్న గ్రామీణ పెద్దలు.', 'Minimum 100 days wage employment; unemployment allowance if work not provided.', '100 రోజుల ఉపాధి హామీ.', ARRAY['Aadhaar','Address proof','Bank/Post office account','Photo'], 'https://nrega.nic.in', 'All India'),
('Soil Health Card Scheme', 'సాయిల్ హెల్త్ కార్డ్', 'Issues soil health cards to farmers with crop-wise recommendations.', 'రైతులకు మట్టి ఆరోగ్య కార్డులు.', 'Agriculture', 'Ministry of Agriculture', 'All farmers across India.', 'భారతదేశంలోని అన్ని రైతులు.', 'Free soil testing every 3 years with nutrient recommendations.', 'ఉచిత మట్టి పరీక్ష.', ARRAY['Aadhaar','Land records'], 'https://soilhealth.dac.gov.in', 'All India'),
('Pradhan Mantri Fasal Bima Yojana', 'PM ఫసల్ బీమా యోజన', 'Crop insurance against natural calamities, pests and diseases.', 'పంటలకు ప్రకృతి విపత్తులు మరియు తెగుళ్ల నుండి బీమా.', 'Agriculture', 'Ministry of Agriculture', 'All farmers (loanee and non-loanee) growing notified crops.', 'నోటిఫై చేయబడిన పంటలు పండించే రైతులు.', 'Up to 90% of sum insured covered; farmer pays 1.5-5% premium.', '90% వరకు బీమా కవరేజ్.', ARRAY['Aadhaar','Land records','Sowing certificate','Bank account'], 'https://pmfby.gov.in', 'All India'),
('Kisan Credit Card (KCC)', 'కిసాన్ క్రెడిట్ కార్డ్', 'Short-term credit for farmers'' cultivation and ancillary needs at low interest.', 'రైతులకు తక్కువ వడ్డీతో రుణం.', 'Agriculture', 'Ministry of Agriculture', 'Farmers (individual/joint), tenants, oral lessees, SHGs, fishermen, dairy farmers.', 'రైతులు, SHGs, మత్స్యకారులు.', 'Credit up to ₹3L @ 7% (with 3% prompt repayment incentive = 4% effective).', '₹3L వరకు 4% వడ్డీతో రుణం.', ARRAY['Aadhaar','PAN','Land records','Bank passbook'], 'https://www.pmkisan.gov.in/Documents/KCC.pdf', 'All India'),
('PM Kisan MaanDhan Yojana', 'PM కిసాన్ మాన్‌ధన్', 'Pension scheme for small and marginal farmers.', 'చిన్న మరియు సన్నకారు రైతులకు పెన్షన్.', 'Agriculture', 'Ministry of Agriculture', 'Small/marginal farmers aged 18-40 with up to 2 hectares land.', '18-40 ఏళ్ళ, 2 హెక్టార్ల వరకు భూమి ఉన్న రైతులు.', '₹3,000/month pension after age 60.', '60 ఏళ్ళ తర్వాత ₹3,000 నెలవారీ పెన్షన్.', ARRAY['Aadhaar','Land records','Bank/Jan Dhan account'], 'https://maandhan.in', 'All India'),
